--
-- Name: fn_audit_checksum(); Type: FUNCTION; Schema: public; Owner: opms
--

CREATE FUNCTION public.fn_audit_checksum() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    -- Unix microseconds: identical to Go's time.Time.UnixMicro().
    NEW.checksum = encode(
        sha256(
            convert_to(
                COALESCE(NEW.tenant_id::text, '') || '|' ||
                COALESCE(NEW.actor_id::text, '') || '|' ||
                COALESCE(NEW.action, '') || '|' ||
                COALESCE(NEW.entity_type, '') || '|' ||
                COALESCE(NEW.entity_id::text, '') || '|' ||
                COALESCE(NEW.changes::text, '') || '|' ||
                ((EXTRACT(EPOCH FROM NEW.timestamp) * 1000000)::bigint)::text,
                'UTF8'
            )
        ),
        'hex'
    );
    RETURN NEW;
END;
$$;


