--
-- Name: fn_validate_cab_meeting_status_transition(); Type: FUNCTION; Schema: public; Owner: opms
--

CREATE FUNCTION public.fn_validate_cab_meeting_status_transition() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF NEW.status IS DISTINCT FROM OLD.status THEN
        IF NOT (
            (OLD.status = 'scheduled' AND NEW.status IN ('in_progress', 'cancelled')) OR
            (OLD.status = 'in_progress' AND NEW.status IN ('completed', 'cancelled'))
        ) THEN
            RAISE EXCEPTION 'invalid CAB meeting transition: % -> %', OLD.status, NEW.status
                USING ERRCODE = '23514';
        END IF;
    END IF;
    RETURN NEW;
END;
$$;


ALTER FUNCTION public.fn_validate_cab_meeting_status_transition() OWNER TO opms;

