    CONSTRAINT tickets_impact_check CHECK ((impact = ANY (ARRAY['critical'::text, 'high'::text, 'medium'::text, 'low'::text]))),
    CONSTRAINT tickets_priority_check CHECK ((priority = ANY (ARRAY['P1_critical'::text, 'P2_high'::text, 'P3_medium'::text, 'P4_low'::text]))),
    CONSTRAINT tickets_status_check CHECK ((status = ANY (ARRAY['logged'::text, 'classified'::text, 'assigned'::text, 'in_progress'::text, 'pending_customer'::text, 'pending_vendor'::text, 'resolved'::text, 'closed'::text, 'cancelled'::text, 'draft'::text, 'submitted'::text, 'assessing'::text, 'cab_review'::text, 'approved'::text, 'rejected'::text, 'deferred'::text, 'scheduled'::text, 'implementing'::text, 'implemented'::text, 'failed'::text, 'rolled_back'::text, 'pir_pending'::text, 'investigating'::text]))),
    CONSTRAINT tickets_type_check CHECK ((type = ANY (ARRAY['incident'::text, 'service_request'::text, 'problem'::text, 'change'::text]))),
    CONSTRAINT tickets_urgency_check CHECK ((urgency = ANY (ARRAY['critical'::text, 'high'::text, 'medium'::text, 'low'::text])))
);

