--
-- Name: mv_executive_summary; Type: MATERIALIZED VIEW; Schema: public; Owner: opms
--

CREATE MATERIALIZED VIEW public.mv_executive_summary AS
 SELECT id AS tenant_id,
    ( SELECT count(*) AS count
           FROM public.policies p
          WHERE ((p.tenant_id = t.id) AND (p.status = 'active'::text))) AS active_policies,
    ( SELECT count(*) AS count
           FROM public.action_items ai
          WHERE ((ai.tenant_id = t.id) AND (ai.status <> ALL (ARRAY['completed'::text, 'cancelled'::text])) AND (ai.due_date < CURRENT_DATE))) AS overdue_actions,
    ( SELECT count(*) AS count
           FROM public.policy_attestations pa
          WHERE ((pa.tenant_id = t.id) AND (pa.status = 'pending'::text))) AS pending_attestations,
    ( SELECT COALESCE(round(avg(o.progress_pct), 2), (0)::numeric) AS "coalesce"
           FROM public.okrs o
          WHERE ((o.tenant_id = t.id) AND (o.status = 'active'::text))) AS avg_okr_progress,
    ( SELECT count(*) AS count
           FROM public.tickets tk
          WHERE ((tk.tenant_id = t.id) AND (tk.status <> ALL (ARRAY['resolved'::text, 'closed'::text, 'cancelled'::text])))) AS open_tickets,
    ( SELECT count(*) AS count
           FROM public.tickets tk
          WHERE ((tk.tenant_id = t.id) AND (tk.status <> ALL (ARRAY['resolved'::text, 'closed'::text, 'cancelled'::text])) AND (tk.priority = 'P1_critical'::text))) AS critical_tickets,
    ( SELECT count(*) AS count
           FROM public.tickets tk
          WHERE ((tk.tenant_id = t.id) AND (tk.status <> ALL (ARRAY['resolved'::text, 'closed'::text, 'cancelled'::text])) AND (tk.priority = 'P1_critical'::text))) AS open_tickets_p1,
    ( SELECT count(*) AS count
           FROM public.tickets tk
          WHERE ((tk.tenant_id = t.id) AND (tk.status <> ALL (ARRAY['resolved'::text, 'closed'::text, 'cancelled'::text])) AND (tk.priority = 'P2_high'::text))) AS open_tickets_p2,
    ( SELECT count(*) AS count
           FROM public.tickets tk
          WHERE ((tk.tenant_id = t.id) AND (tk.status <> ALL (ARRAY['resolved'::text, 'closed'::text, 'cancelled'::text])) AND (tk.priority = 'P3_medium'::text))) AS open_tickets_p3,
    ( SELECT count(*) AS count
           FROM public.tickets tk
          WHERE ((tk.tenant_id = t.id) AND (tk.status <> ALL (ARRAY['resolved'::text, 'closed'::text, 'cancelled'::text])) AND (tk.priority = 'P4_low'::text))) AS open_tickets_p4,
    ( SELECT
                CASE
                    WHEN (count(*) FILTER (WHERE (tk.sla_resolution_met IS NOT NULL)) = 0) THEN (100)::numeric
                    ELSE round((((count(*) FILTER (WHERE (tk.sla_resolution_met = true)))::numeric / NULLIF((count(*) FILTER (WHERE (tk.sla_resolution_met IS NOT NULL)))::numeric, (0)::numeric)) * (100)::numeric), 2)
                END AS round
           FROM public.tickets tk
          WHERE (tk.tenant_id = t.id)) AS sla_compliance_pct,
    ( SELECT COALESCE(round(avg((EXTRACT(epoch FROM (tk.resolved_at - tk.created_at)) / 60.0)), 2), (0)::numeric) AS "coalesce"
           FROM public.tickets tk
          WHERE ((tk.tenant_id = t.id) AND (tk.resolved_at IS NOT NULL))) AS mttr_minutes,
    ( SELECT COALESCE(round(avg((EXTRACT(epoch FROM (tk.first_response_at - tk.created_at)) / 60.0)), 2), (0)::numeric) AS "coalesce"
           FROM public.tickets tk
          WHERE ((tk.tenant_id = t.id) AND (tk.first_response_at IS NOT NULL))) AS mtta_minutes,
    ( SELECT count(*) AS count
           FROM public.tickets tk
          WHERE ((tk.tenant_id = t.id) AND (tk.status <> ALL (ARRAY['resolved'::text, 'closed'::text, 'cancelled'::text])) AND (tk.created_at < (now() - '30 days'::interval)))) AS backlog_over_30_days,
    ( SELECT count(*) AS count
           FROM public.projects pj
          WHERE ((pj.tenant_id = t.id) AND (pj.status = 'active'::text))) AS active_projects,
    ( SELECT count(*) AS count
           FROM public.projects pj
          WHERE ((pj.tenant_id = t.id) AND (pj.rag_status = 'green'::text))) AS projects_rag_green,
    ( SELECT count(*) AS count
           FROM public.projects pj
          WHERE ((pj.tenant_id = t.id) AND (pj.rag_status = 'amber'::text))) AS projects_rag_amber,
    ( SELECT count(*) AS count
           FROM public.projects pj
          WHERE ((pj.tenant_id = t.id) AND (pj.rag_status = 'red'::text))) AS projects_rag_red,
    ( SELECT
                CASE
                    WHEN (count(*) FILTER (WHERE ((pj.actual_end IS NOT NULL) AND (pj.planned_end IS NOT NULL))) = 0) THEN (0)::numeric
                    ELSE round((((count(*) FILTER (WHERE ((pj.actual_end IS NOT NULL) AND (pj.planned_end IS NOT NULL) AND (pj.actual_end <= pj.planned_end))))::numeric / NULLIF((count(*) FILTER (WHERE ((pj.actual_end IS NOT NULL) AND (pj.planned_end IS NOT NULL))))::numeric, (0)::numeric)) * (100)::numeric), 2)
                END AS round
           FROM public.projects pj
          WHERE (pj.tenant_id = t.id)) AS on_time_delivery_pct,
    ( SELECT
                CASE
                    WHEN (count(*) = 0) THEN (0)::numeric
                    ELSE round((((count(*) FILTER (WHERE ((m.status = 'completed'::text) OR (m.actual_date IS NOT NULL))))::numeric / (count(*))::numeric) * (100)::numeric), 2)
                END AS round
           FROM public.milestones m
          WHERE (m.tenant_id = t.id)) AS milestone_burn_down_pct,
    ( SELECT count(*) AS count
           FROM public.assets a
          WHERE ((a.tenant_id = t.id) AND (a.status = 'active'::text))) AS active_assets,
    ( SELECT COALESCE(jsonb_object_agg(s.type, s.count), '{}'::jsonb) AS "coalesce"
           FROM ( SELECT a.type,
                    (count(*))::integer AS count
                   FROM public.assets a
                  WHERE (a.tenant_id = t.id)
                  GROUP BY a.type) s) AS asset_counts_by_type,
    ( SELECT COALESCE(jsonb_object_agg(s.status, s.count), '{}'::jsonb) AS "coalesce"
           FROM ( SELECT a.status,
                    (count(*))::integer AS count
                   FROM public.assets a
                  WHERE (a.tenant_id = t.id)
                  GROUP BY a.status) s) AS asset_counts_by_status,
    ( SELECT count(*) AS count
           FROM public.licenses l
          WHERE ((l.tenant_id = t.id) AND (l.compliance_status = 'over_deployed'::text))) AS over_deployed_licenses,
    ( SELECT
                CASE
                    WHEN (count(*) = 0) THEN (100)::numeric
                    ELSE round((((count(*) FILTER (WHERE (l.compliance_status = 'compliant'::text)))::numeric / (count(*))::numeric) * (100)::numeric), 2)
                END AS round
           FROM public.licenses l
          WHERE (l.tenant_id = t.id)) AS license_compliance_pct,
    ( SELECT count(*) AS count
           FROM public.warranties w
          WHERE ((w.tenant_id = t.id) AND ((w.end_date >= CURRENT_DATE) AND (w.end_date <= (CURRENT_DATE + 90))))) AS warranties_expiring_90_days,
    ( SELECT count(*) AS count
           FROM public.risks rk
          WHERE ((rk.tenant_id = t.id) AND (rk.status <> ALL (ARRAY['closed'::text, 'accepted'::text])) AND ((rk.risk_score >= 12) AND (rk.risk_score <= 19)))) AS high_risks,
    ( SELECT count(*) AS count
           FROM public.risks rk
          WHERE ((rk.tenant_id = t.id) AND (rk.status <> ALL (ARRAY['closed'::text, 'accepted'::text])) AND (rk.risk_score >= 20))) AS critical_risks,
    ( SELECT COALESCE(round(avg(a.readiness_score), 2), (0)::numeric) AS "coalesce"
           FROM public.grc_audits a
          WHERE (a.tenant_id = t.id)) AS audit_readiness_score,
    ( SELECT COALESCE(round(avg(arc.completion_rate), 2), (0)::numeric) AS "coalesce"
           FROM public.access_review_campaigns arc
          WHERE ((arc.tenant_id = t.id) AND (arc.status = ANY (ARRAY['active'::text, 'review'::text, 'completed'::text])))) AS access_review_completion_pct,
    ( SELECT COALESCE(round(avg(ca.allocation_pct), 2), (0)::numeric) AS "coalesce"
           FROM public.capacity_allocations ca
          WHERE ((ca.tenant_id = t.id) AND (ca.period_start <= CURRENT_DATE) AND (ca.period_end >= CURRENT_DATE))) AS team_capacity_utilization_pct,
    ( SELECT count(*) AS count
           FROM public.training_records tr
          WHERE ((tr.tenant_id = t.id) AND (((tr.status = ANY (ARRAY['planned'::text, 'in_progress'::text])) AND ((tr.created_at)::date < (CURRENT_DATE - 30))) OR ((tr.expiry_date IS NOT NULL) AND (tr.expiry_date < CURRENT_DATE))))) AS overdue_training_certs,
    ( SELECT count(*) AS count
           FROM public.training_records tr
          WHERE ((tr.tenant_id = t.id) AND ((tr.expiry_date >= CURRENT_DATE) AND (tr.expiry_date <= (CURRENT_DATE + 30))) AND (tr.status <> 'expired'::text))) AS expiring_certs,
    now() AS refreshed_at
   FROM public.tenants t
  WITH NO DATA;


ALTER MATERIALIZED VIEW public.mv_executive_summary OWNER TO opms;

