--
-- Data for Name: audit_findings; Type: TABLE DATA; Schema: public; Owner: opms
--

COPY public.audit_findings (id, audit_id, tenant_id, finding_number, title, description, severity, status, remediation_plan, owner_id, due_date, closed_at, evidence_of_remediation, created_at, updated_at) FROM stdin;
f0000001-0000-4000-b000-000000000001	a0000001-0000-4000-b000-000000000001	00000000-0000-0000-0000-000000000001	FND-0001	Privileged access review not conducted quarterly	The quarterly review of privileged accounts (domain admins, database admins, and application super-users) was not performed in Q2 and Q3 2025, resulting in 14 stale admin accounts remaining active.	high	closed	Implement automated quarterly PAM review via CyberArk and integrate with OPMS workflow for sign-off.	7d3f9d2a-0340-a89e-c8cb-03ca50a5d0e8	2025-12-31	2025-12-15 09:00:00+00	{}	2025-11-01 09:00:00+00	2025-12-15 09:00:00+00
f0000001-0000-4000-b000-000000000002	a0000001-0000-4000-b000-000000000001	00000000-0000-0000-0000-000000000001	FND-0002	Missing encryption at rest for legacy file shares	Three legacy network file shares containing classified documents were found without BitLocker or equivalent encryption at rest, violating control A.8.24.	medium	closed	Migrate file shares to encrypted SharePoint Online or enable BitLocker on file server volumes.	f3947e51-26fa-f488-4a13-e65c608d2e7b	2026-01-31	2026-01-20 13:00:00+00	{}	2025-11-05 09:00:00+00	2026-01-20 13:00:00+00
f0000001-0000-4000-b000-000000000003	a0000001-0000-4000-b000-000000000001	00000000-0000-0000-0000-000000000001	FND-0003	Incident response plan not tested in 12 months	The Information Security Incident Response Plan (ISIRP) has not been tested via tabletop exercise since October 2024, exceeding the annual testing requirement.	medium	accepted	Schedule tabletop exercise for Q1 2026 with scenario based on recent ransomware threats.	90377934-1644-8547-b018-c4bb2449aaef	2026-03-31	\N	{}	2025-11-10 09:00:00+00	2025-12-01 09:00:00+00
f0000001-0000-4000-b000-000000000004	a0000001-0000-4000-b000-000000000002	00000000-0000-0000-0000-000000000001	FND-0001	IT risk register not updated after infrastructure migration	The enterprise IT risk register was not refreshed after the cloud migration completed in Q1 2025. Several new cloud-specific risks (misconfigured storage buckets, identity federation) were not captured.	high	closed	Conduct comprehensive risk reassessment incorporating cloud-native risks. Update OPMS risk register module.	e712da03-d912-0288-98e7-7907f066d7cd	2025-10-31	2025-10-28 09:00:00+00	{}	2025-08-15 09:00:00+00	2025-10-28 09:00:00+00
f0000001-0000-4000-b000-000000000005	a0000001-0000-4000-b000-000000000002	00000000-0000-0000-0000-000000000001	FND-0002	Change advisory board records incomplete	CAB meeting minutes for 6 out of 24 fortnightly sessions were missing or incomplete, with no documented risk assessment for 12 emergency changes.	medium	closed	Enforce mandatory CAB minute templates in OPMS and require digital sign-off before change implementation.	f3947e51-26fa-f488-4a13-e65c608d2e7b	2025-11-30	2025-11-25 13:00:00+00	{}	2025-08-20 09:00:00+00	2025-11-25 13:00:00+00
f0000001-0000-4000-b000-000000000006	a0000001-0000-4000-b000-000000000003	00000000-0000-0000-0000-000000000001	FND-0001	CCTV blind spots identified in server room corridor	Two corridor sections between server racks B3–B5 and C1–C3 have no CCTV coverage due to camera positioning. Physical access logs show 340 entries in these corridors in the past 90 days.	high	remediation_planned	Install two additional PTZ cameras in identified blind spots. Target completion: April 2026.	7d3f9d2a-0340-a89e-c8cb-03ca50a5d0e8	2026-04-30	\N	{}	2026-03-10 09:00:00+00	2026-03-10 09:00:00+00
f0000001-0000-4000-b000-000000000007	a0000001-0000-4000-b000-000000000003	00000000-0000-0000-0000-000000000001	FND-0002	UPS battery replacement overdue by 6 months	Battery replacement for UPS Unit 2 (APC Symmetra PX 250kW) was due in September 2025 but has not been completed. Runtime testing shows degraded capacity of 68% vs. rated 100%.	critical	in_remediation	Emergency procurement of replacement battery modules initiated. Interim: reduce non-critical load on UPS Unit 2.	c59b492e-b071-8565-6194-633cad81d471	2026-04-15	\N	{}	2026-03-12 09:00:00+00	2026-03-20 09:00:00+00
f0000001-0000-4000-b000-000000000008	a0000001-0000-4000-b000-000000000003	00000000-0000-0000-0000-000000000001	FND-0003	Environmental monitoring alerts not routing to on-call team	Temperature and humidity alerts from the BMS system are configured to email a distribution list that includes two former staff members and excludes the current on-call duty roster.	medium	open	\N	f3947e51-26fa-f488-4a13-e65c608d2e7b	2026-04-30	\N	{}	2026-03-15 09:00:00+00	2026-03-15 09:00:00+00
f0000001-0000-4000-b000-000000000009	a0000001-0000-4000-b000-000000000004	00000000-0000-0000-0000-000000000001	FND-0001	Data subject access request process exceeds 30-day SLA	Analysis of 23 DSARs received in 2025 shows an average response time of 42 days, exceeding the NDPR-mandated 30-day window. Three requests took over 60 days.	high	remediation_planned	Automate DSAR intake via self-service portal. Assign dedicated DSAR coordinator in ITD.	90377934-1644-8547-b018-c4bb2449aaef	2026-05-31	\N	{}	2026-03-01 09:00:00+00	2026-03-15 09:00:00+00
f0000001-0000-4000-b000-000000000010	a0000001-0000-4000-b000-000000000004	00000000-0000-0000-0000-000000000001	FND-0002	No DPIA conducted for new HR analytics platform	The HR Performance Analytics module (deployed January 2026) processes employee biometric and performance data but no Data Protection Impact Assessment was conducted prior to deployment.	critical	open	\N	e712da03-d912-0288-98e7-7907f066d7cd	2026-04-30	\N	{}	2026-03-05 09:00:00+00	2026-03-05 09:00:00+00
f0000001-0000-4000-b000-000000000011	a0000001-0000-4000-b000-000000000004	00000000-0000-0000-0000-000000000001	FND-0003	Consent records not centrally managed	Data processing consent records are stored in five separate systems (CRM, HR portal, email archives, paper forms, helpdesk) with no consolidated consent management platform.	medium	open	\N	90377934-1644-8547-b018-c4bb2449aaef	2026-06-30	\N	{}	2026-03-08 09:00:00+00	2026-03-08 09:00:00+00
f0000001-0000-4000-b000-000000000012	a0000001-0000-4000-b000-000000000007	00000000-0000-0000-0000-000000000001	FND-0001	P1 incident resolution time exceeds target SLA	Average P1 incident resolution time is 6.2 hours against a 4-hour SLA target. Root cause analysis shows escalation delays between L1 and L2 support.	high	in_remediation	Implement automated escalation rules in OPMS ITSM module. Conduct L1-L2 handoff training.	f3947e51-26fa-f488-4a13-e65c608d2e7b	2026-04-30	\N	{}	2026-03-15 09:00:00+00	2026-03-22 09:00:00+00
